using UnityEngine;
public class Script {
  public static object Main() {
    var sb = new System.Text.StringBuilder();

    // Find CNC2SpindleController and print its hierarchy
    var spindle = GameObject.FindFirstObjectByType<CNC2SpindleController>();
    if (spindle == null) { return "CNC2SpindleController not found"; }

    sb.AppendLine("SpindleController on: " + spindle.gameObject.name);

    // Print ancestor chain
    Transform t = spindle.transform;
    sb.AppendLine("\n--- Ancestor chain (bottom to top) ---");
    while (t != null) {
      sb.AppendLine("  " + t.name + "  localPos=" + t.localPosition.ToString("F5"));
      t = t.parent;
    }

    // Try to find cncCutter anywhere
    sb.AppendLine("\n--- Searching for 'cncCutter' in scene ---");
    var all = GameObject.FindObjectsByType<Transform>(FindObjectsSortMode.None);
    foreach (var tr in all) {
      if (tr.name.ToLower().Contains("cnccutter") || tr.name.ToLower().Contains("cnc cutter"))
        sb.AppendLine("  FOUND: '" + tr.name + "'  parent='" + (tr.parent?.name ?? "root") + "'");
    }

    // Also check children of spindleController's root
    sb.AppendLine("\n--- Root children (2 levels) ---");
    Transform root = spindle.transform;
    while (root.parent != null) root = root.parent;
    foreach (Transform child in root) {
      sb.AppendLine("  [" + child.name + "]");
      foreach (Transform gc in child)
        sb.AppendLine("    [" + gc.name + "]");
    }

    return sb.ToString();
  }
}
